class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False

        freq = [0] * 26
        for a, b in zip(s, t):
            diff = (ord(b) - ord(a)) % 26
            if diff:
                freq[diff] += 1

        max_needed = 0
        for d in range(1, 26):
            if freq[d] == 0:
                continue
            cycles = freq[d] - 1
            last_occurrence = cycles * 26 + d
            max_needed = max(max_needed, last_occurrence)

        return max_needed <= k

